---@class LBattleBuffActData
local LBattleBuffActData = classX("LBattleBuffActData",nil)
-----------------------------------------------------------------
-----------------------------------------------------------------
function LBattleBuffActData:ctor()

end

function LBattleBuffActData:SetData(skillExpressId)
    local skillShowEffEf = GameTable.SnakeSkillExpressionRef[skillExpressId]
    if not skillShowEffEf then
        if LOG_INFO_ENABLED then
            printError("不能存在的 skillExpressId id : "..tostring(skillExpressId))
        end
        return false
    end

    local playEff = skillShowEffEf.playEff
    local playEffectMap = {}

    self._playEffectMap = playEffectMap

    --重新组织 结构，可以方便不需要配置表 就可以自己生成 表演结构
    self._playEffectList = self:ParsePlayEff(playEffectMap,playEff)

    --根据延迟时间排序
    local sortFunc = function (a,b)
        return a.delayTime < b.delayTime
    end
    table.sort(self._playEffectList,sortFunc)


    --预测大概时间，只计算一层嵌套
    self._skillShowTime = self:CalcSkillTime(self._playEffectList)
end

function LBattleBuffActData:ParsePlayEff(hadMap,playEffListStr)
    local arrPlayEffId = string.split(playEffListStr or "","|") or {}
    local playEffList = {}

    for k,strId in ipairs(arrPlayEffId) do
        local refId = tonumber(strId)
        local skillVfxRef = GameTable.SnakeSkillVfxRef[refId]
        if skillVfxRef then
            --防止错误填写循环索引
            local data = hadMap[refId]
            if not data then
                data = {
                    refId = refId,
                    effType = skillVfxRef.effType,
                    effRes = skillVfxRef.effRes,
                    actionReset = skillVfxRef.actionReset,
                    delayTime = skillVfxRef.delayTime,
                    playTime = skillVfxRef.playTime,
                    dissipateTime = skillVfxRef.dissipateTime,
                    moveSpeed = skillVfxRef.moveSpeed,
                    nextPlay = skillVfxRef.nextPlay,
                    excursionIObject = skillVfxRef.excursionIObject,
                    effOffsetStart = self:ParseOffset(skillVfxRef.effOffsetStart),
                    effOffsetEnd = self:ParseOffset(skillVfxRef.effOffsetEnd),
                    effTarget = skillVfxRef.effTarget,
                    bulletCdTime = skillVfxRef.bulletCdTime,
                    effTargetIndex = skillVfxRef.effTargetIndex,
                    bulletTrack = skillVfxRef.bulletTrack,
                    playNum = {},
                    nextPlayList = {},
                    soundBattle = skillVfxRef.soundBattle or "",
                    talkTxt =I18nText(skillVfxRef.talkTxt),
                }
                hadMap[refId] = data
                table.insert(playEffList,data)

            end
        end
    end
    return playEffList
end

function LBattleBuffActData:ParseOffset(str)
    if string.isempty(str) then return Vector3.zero end
    local offset = LxDataHelper.ParseVector(str)
    return offset
end

function LBattleBuffActData:GetPlayList()
    return self._playEffectList or {}
end

function LBattleBuffActData:CalcSkillTime(playeEffList)
    local maxTime = 0
    for k,v in pairs(playeEffList) do
        local max = v.delayTime + v.playTime
        if max > maxTime then
            maxTime = max
        end
    end
    return maxTime
end


return LBattleBuffActData